ICON_PNG_B64 = (
    ""
)

BG_DARK      = "#1A1D23"
BG_PANEL     = "#22262F"
BG_INPUT     = "#2A2F3A"
BG_ROW_ODD   = "#22262F"
BG_ROW_EVEN  = "#1E2229"
BG_ROW_SEL   = "#1E3A5F"
BORDER       = "#333844"
TEXT_PRIMARY = "#E8EAF0"
TEXT_MUTED   = "#7B8196"
ACCENT       = "#4A9EFF"
ACCENT_DARK  = "#1A5FA8"
HIGHLIGHT    = "#FFB347"
GREEN        = "#3DAA6E"
RED          = "#E05252"

STYLESHEET = f"""
QMainWindow, QWidget {{
    background-color: {BG_DARK};
    color: {TEXT_PRIMARY};
    font-family: 'Segoe UI', 'Ubuntu', sans-serif;
    font-size: 13px;
}}
QLabel {{ color: {TEXT_PRIMARY}; }}
QLineEdit {{
    background-color: {BG_INPUT};
    border: 1px solid {BORDER};
    border-radius: 6px;
    padding: 6px 10px;
    color: {TEXT_PRIMARY};
    selection-background-color: {ACCENT_DARK};
}}
QLineEdit:focus {{ border: 1px solid {ACCENT}; }}
QPushButton {{
    background-color: {BG_INPUT};
    border: 1px solid {BORDER};
    border-radius: 6px;
    padding: 6px 14px;
    color: {TEXT_PRIMARY};
}}
QPushButton:hover {{ background-color: {BORDER}; }}
QPushButton#btn_search {{
    background-color: {GREEN}; border: none;
    color: #fff; font-weight: bold; padding: 8px 20px;
}}
QPushButton#btn_search:hover {{ background-color: #35956A; }}
QPushButton#btn_search:disabled {{ background-color: #2A4A3A; color: #668866; }}
QPushButton#btn_stop {{
    background-color: {RED}; border: none;
    color: #fff; font-weight: bold; padding: 8px 20px;
}}
QPushButton#btn_stop:hover {{ background-color: #C04040; }}
QPushButton#btn_stop:disabled {{ background-color: #3A2222; color: #885555; }}
QPushButton#btn_browse {{
    background-color: {ACCENT_DARK}; border: none; color: #fff; padding: 6px 14px;
}}
QPushButton#btn_browse:hover {{ background-color: {ACCENT}; }}
QCheckBox {{ color: {TEXT_MUTED}; spacing: 6px; }}
QCheckBox::indicator {{
    width: 16px; height: 16px;
    border: 1px solid {BORDER}; border-radius: 4px; background: {BG_INPUT};
}}
QCheckBox::indicator:checked {{ background: {ACCENT}; border-color: {ACCENT}; }}
QTableView {{
    background-color: {BG_PANEL}; border: 1px solid {BORDER};
    border-radius: 8px; gridline-color: {BORDER};
    selection-background-color: {BG_ROW_SEL}; outline: none;
}}
QTableView::item {{ padding: 4px 8px; border: none; }}
QTableView::item:selected {{ background-color: {BG_ROW_SEL}; color: {TEXT_PRIMARY}; }}
QHeaderView::section {{
    background-color: {BG_INPUT}; color: {TEXT_MUTED};
    border: none; border-right: 1px solid {BORDER}; border-bottom: 1px solid {BORDER};
    padding: 6px 10px; font-weight: bold; font-size: 12px;
    text-transform: uppercase; letter-spacing: 1px;
}}
QScrollBar:vertical {{ background: {BG_DARK}; width: 8px; border-radius: 4px; }}
QScrollBar::handle:vertical {{
    background: {BORDER}; border-radius: 4px; min-height: 30px;
}}
QScrollBar::handle:vertical:hover {{ background: {TEXT_MUTED}; }}
QScrollBar:horizontal {{ background: {BG_DARK}; height: 8px; border-radius: 4px; }}
QScrollBar::handle:horizontal {{ background: {BORDER}; border-radius: 4px; }}
QStatusBar {{ color: {TEXT_MUTED}; background: {BG_DARK}; font-size: 12px; }}
QProgressBar {{
    background-color: {BG_INPUT}; border: none;
    border-radius: 3px; height: 4px; text-align: center;
}}
QProgressBar::chunk {{ background-color: {ACCENT}; border-radius: 3px; }}
QFrame#separator {{ background-color: {BORDER}; max-height: 1px; }}
"""
